        // 3. Notify user of successful application
        // 4. Update UI to show discount applied
        
        // Example of how you might store this:
        UserDefaults.standard.set(code, forKey: "activePromoCode")
        UserDefaults.standard.set(discount, forKey: "activePromoDiscount")
        
